// Count paid customers from Notion data
const items = $input.all();
const current = items.length; // Each row = 1 customer
const target = 28;
const remaining = target - current;
const revenue = current * 350; // Average price
const targetRevenue = target * 350;

// Deadline
const deadline = new Date('2026-04-05T23:59:59');
const now = new Date();
const hoursLeft = Math.max(0, Math.round((deadline - now) / (1000 * 60 * 60)));
const daysLeft = Math.max(0, Math.round(hoursLeft / 24));

// Status
const pace = current / Math.max(1, (28 - daysLeft)); // customers per day
const needed = remaining / Math.max(1, daysLeft);
let status = '';
if (pace >= needed) status = '🟢 AHEAD';
else if (pace >= needed * 0.7) status = '🟡 ON TRACK';
else status = '🔴 BEHIND';

return {
  json: {
    current,
    target,
    remaining,
    revenue,
    targetRevenue,
    daysLeft,
    hoursLeft,
    status,
    pace: Math.round(pace * 10) / 10,
    needed: Math.round(needed * 10) / 10
  }
};
